1	export type Cell = [number, number];
2	
3	const NEIGHBOR_OFFSETS: Cell[] = [
4	  [-1, -1], [-1, 0], [-1, 1],
5	  [0, -1],           [0, 1],
6	  [1, -1],  [1, 0],  [1, 1],
7	];
8	
9	const cellKey = ([x, y]: Cell): string => `${x},${y}`;
10	
11	const survives = (neighborCount: number, isAlive: boolean): boolean =>
12	  neighborCount === 3 || (neighborCount === 2 && isAlive);
13	
14	export function nextGeneration(livingCells: Cell[]): Cell[] {
15	  const liveKeys = new Set(livingCells.map(cellKey));
16	  const candidates = new Map<string, { cell: Cell; count: number }>();
17	
18	  for (const [x, y] of livingCells) {
19	    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
20	      const neighbor: Cell = [x + dx, y + dy];
21	      const key = cellKey(neighbor);
22	      const entry = candidates.get(key) ?? { cell: neighbor, count: 0 };
23	      entry.count++;
24	      candidates.set(key, entry);
25	    }
26	  }
27	
28	  const result: Cell[] = [];
29	  for (const [key, { cell, count }] of candidates) {
30	    if (survives(count, liveKeys.has(key))) {
31	      result.push(cell);
32	    }
33	  }
34	  return result;
35	}
36

1	import { describe, it, expect } from "vitest";
2	import { nextGeneration, type Cell } from "./game-of-life.js";
3	
4	describe("Game of Life - nextGeneration", () => {
5	  it("should return empty array for empty input", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("should kill a single live cell (underpopulation: 0 neighbors)", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("should kill two adjacent live cells (underpopulation: 1 neighbor each)", () => {
12	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
13	  });
14	  it("should preserve a 2x2 block (still life: each cell has 3 neighbors)", () => {
15	    const block: Cell[] = [[0, 0], [1, 0], [0, 1], [1, 1]];
16	    const result = nextGeneration(block);
17	    expect(result).toHaveLength(4);
18	    expect(result).toEqual(expect.arrayContaining(block));
19	  });
20	  it("should toggle a vertical blinker to horizontal (survival + reproduction)", () => {
21	    const vertical: Cell[] = [[0, 0], [0, 1], [0, 2]];
22	    const horizontal: Cell[] = [[-1, 1], [0, 1], [1, 1]];
23	    const result = nextGeneration(vertical);
24	    expect(result).toHaveLength(3);
25	    expect(result).toEqual(expect.arrayContaining(horizontal));
26	  });
27	  it("should kill the center of a full 3x3 square (overpopulation: 8 neighbors)", () => {
28	    const square: Cell[] = [
29	      [0, 0], [1, 0], [2, 0],
30	      [0, 1], [1, 1], [2, 1],
31	      [0, 2], [1, 2], [2, 2],
32	    ];
33	    const result = nextGeneration(square);
34	    expect(result).not.toContainEqual([1, 1]);
35	  });
36	  it("should handle negative coordinates", () => {
37	    const verticalBlinker: Cell[] = [[-5, -5], [-5, -4], [-5, -3]];
38	    const horizontalBlinker: Cell[] = [[-6, -4], [-5, -4], [-4, -4]];
39	    const result = nextGeneration(verticalBlinker);
40	    expect(result).toHaveLength(3);
41	    expect(result).toEqual(expect.arrayContaining(horizontalBlinker));
42	  });
43	});
