export function nextGeneration(livingCells: Cell[]): Cell[] {
  const liveKeys = new Set(livingCells.map(cellKey));
  const candidates = new Map<string, { cell: Cell; count: number }>();

  for (const [x, y] of livingCells) {
    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
      const neighbor: Cell = [x + dx, y + dy];
      const key = cellKey(neighbor);
      const entry = candidates.get(key) ?? { cell: neighbor, count: 0 };
      entry.count++;
      candidates.set(key, entry);
    }
  }

  const result: Cell[] = [];
  for (const [key, { cell, count }] of candidates) {
    if (survives(count, liveKeys.has(key))) {
      result.push(cell);
    }
  }
  return result;
}

